import 'package:flutter/material.dart';\nimport 'package:mystic_hub/config/theme/app_theme.dart';\n\nclass AdminPanelPage extends StatefulWidget {\n  const AdminPanelPage({Key? key}) : super(key: key);\n\n  @override\n  State<AdminPanelPage> createState() => _AdminPanelPageState();\n}\n\nclass _AdminPanelPageState extends State<AdminPanelPage> {\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('Admin Panel'),\n        centerTitle: true,\n      ),\n      body: Container(\n        decoration: BoxDecoration(\n          gradient: LinearGradient(\n            begin: Alignment.topLeft,\n            end: Alignment.bottomRight,\n            colors: [\n              AppColors.bgDarkerNavy,\n              AppColors.bgDarkNavy,\n            ],\n          ),\n        ),\n        child: SafeArea(\n          child: CustomScrollView(\n            slivers: [\n              SliverPadding(\n                padding: const EdgeInsets.all(16),\n                sliver: SliverList(\n                  delegate: SliverChildListDelegate([\n                    // Admin Warning\n                    Container(\n                      padding: const EdgeInsets.all(12),\n                      decoration: BoxDecoration(\n                        color: AppColors.warning.withOpacity(0.2),\n                        borderRadius: BorderRadius.circular(12),\n                        border: Border.all(\n                          color: AppColors.warning,\n                          width: 1,\n                        ),\n                      ),\n                      child: Row(\n                        children: [\n                          const Icon(\n                            Icons.security,\n                            color: AppColors.warning,\n                          ),\n                          const SizedBox(width: 12),\n                          Expanded(\n                            child: Text(\n                              'Admin-only access. Manage content and settings carefully.',\n                              style: Theme.of(context)\n                                  .textTheme\n                                  .bodySmall\n                                  ?.copyWith(color: AppColors.warning),\n                            ),\n                          ),\n                        ],\n                      ),\n                    ),\n                    const SizedBox(height: 24),\n\n                    // Admin Sections\n                    Text(\n                      'Management',\n                      style: Theme.of(context).textTheme.headlineMedium,\n                    ),\n                    const SizedBox(height: 12),\n                    _buildAdminOption(\n                      context,\n                      icon: Icons.school,\n                      title: 'Add Lessons',\n                      description: 'Create new blockchain lessons for academy',\n                      onTap: () => _showLessonForm(context),\n                    ),\n                    const SizedBox(height: 12),\n                    _buildAdminOption(\n                      context,\n                      icon: Icons.image,\n                      title: 'Add Memes',\n                      description: 'Upload new memes to the meme realm',\n                      onTap: () => _showMemeForm(context),\n                    ),\n                    const SizedBox(height: 12),\n                    _buildAdminOption(\n                      context,\n                      icon: Icons.announcement,\n                      title: 'Create Announcements',\n                      description: 'Post important announcements to users',\n                      onTap: () => _showAnnouncementForm(context),\n                    ),\n                    const SizedBox(height: 12),\n                    _buildAdminOption(\n                      context,\n                      icon: Icons.assignment,\n                      title: 'Create Daily Quests',\n                      description: 'Setup daily challenges and rewards',\n                      onTap: () => _showQuestForm(context),\n                    ),\n\n                    const SizedBox(height: 24),\n\n                    // Statistics\n                    Text(\n                      'Platform Statistics',\n                      style: Theme.of(context).textTheme.headlineMedium,\n                    ),\n                    const SizedBox(height: 12),\n                    Row(\n                      children: [\n                        Expanded(\n                          child: _buildStatCard(\n                            'Total Users',\n                            '2,450',\n                            Icons.people,\n                            AppColors.accentCyan,\n                          ),\n                        ),\n                        const SizedBox(width: 12),\n                        Expanded(\n                          child: _buildStatCard(\n                            'Active Today',\n                            '842',\n                            Icons.trending_up,\n                            AppColors.accentPink,\n                          ),\n                        ),\n                      ],\n                    ),\n                    const SizedBox(height: 12),\n                    Row(\n                      children: [\n                        Expanded(\n                          child: _buildStatCard(\n                            'Total Points',\n                            '12.5M',\n                            Icons.star,\n                            AppColors.primaryPurple,\n                          ),\n                        ),\n                        const SizedBox(width: 12),\n                        Expanded(\n                          child: _buildStatCard(\n                            'Quests Done',\n                            '5,230',\n                            Icons.check_circle,\n                            Colors.amber,\n                          ),\n                        ),\n                      ],\n                    ),\n\n                    const SizedBox(height: 32),\n                  ]),\n                ),\n              ),\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n\n  Widget _buildAdminOption(\n    BuildContext context, {\n    required IconData icon,\n    required String title,\n    required String description,\n    required VoidCallback onTap,\n  }) {\n    return GestureDetector(\n      onTap: onTap,\n      child: Container(\n        padding: const EdgeInsets.all(12),\n        decoration: BoxDecoration(\n          color: AppColors.bgCard,\n          borderRadius: BorderRadius.circular(12),\n          border: Border.all(\n            color: AppColors.primaryPurple.withOpacity(0.3),\n            width: 1,\n          ),\n        ),\n        child: Row(\n          children: [\n            Container(\n              padding: const EdgeInsets.all(10),\n              decoration: BoxDecoration(\n                color: AppColors.primaryPurple.withOpacity(0.2),\n                borderRadius: BorderRadius.circular(8),\n              ),\n              child: Icon(icon, color: AppColors.accentCyan),\n            ),\n            const SizedBox(width: 12),\n            Expanded(\n              child: Column(\n                crossAxisAlignment: CrossAxisAlignment.start,\n                children: [\n                  Text(\n                    title,\n                    style: Theme.of(context).textTheme.titleSmall,\n                  ),\n                  const SizedBox(height: 2),\n                  Text(\n                    description,\n                    style: Theme.of(context).textTheme.bodySmall?.copyWith(\n                          color: AppColors.textSecondary,\n                        ),\n                    maxLines: 1,\n                    overflow: TextOverflow.ellipsis,\n                  ),\n                ],\n              ),\n            ),\n            const Icon(Icons.arrow_forward_ios, size: 16),\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget _buildStatCard(\n    String label,\n    String value,\n    IconData icon,\n    Color color,\n  ) {\n    return Container(\n      padding: const EdgeInsets.all(12),\n      decoration: BoxDecoration(\n        color: AppColors.bgCard,\n        borderRadius: BorderRadius.circular(12),\n        border: Border.all(\n          color: color.withOpacity(0.3),\n          width: 1,\n        ),\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Icon(icon, color: color, size: 24),\n          const SizedBox(height: 8),\n          Text(\n            label,\n            style: Theme.of(context)\n                .textTheme\n                .labelSmall\n                ?.copyWith(color: AppColors.textSecondary),\n          ),\n          const SizedBox(height: 4),\n          Text(\n            value,\n            style: Theme.of(context).textTheme.titleSmall?.copyWith(\n                  color: color,\n                  fontWeight: FontWeight.bold,\n                ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  void _showLessonForm(BuildContext context) {\n    showModalBottomSheet(\n      context: context,\n      backgroundColor: AppColors.bgCard,\n      builder: (context) => Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Text(\n              'Add New Lesson',\n              style: Theme.of(context).textTheme.headlineSmall,\n            ),\n            const SizedBox(height: 16),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Lesson Title',\n                hintText: 'Enter lesson title',\n              ),\n            ),\n            const SizedBox(height: 12),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Description',\n                hintText: 'Enter lesson description',\n              ),\n              maxLines: 3,\n            ),\n            const SizedBox(height: 12),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Content',\n                hintText: 'Enter lesson content',\n              ),\n              maxLines: 4,\n            ),\n            const SizedBox(height: 16),\n            SizedBox(\n              width: double.infinity,\n              child: ElevatedButton(\n                onPressed: () => Navigator.pop(context),\n                child: const Text('Add Lesson'),\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _showMemeForm(BuildContext context) {\n    showModalBottomSheet(\n      context: context,\n      backgroundColor: AppColors.bgCard,\n      builder: (context) => Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Text(\n              'Add New Meme',\n              style: Theme.of(context).textTheme.headlineSmall,\n            ),\n            const SizedBox(height: 16),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Meme Title',\n                hintText: 'Enter meme title',\n              ),\n            ),\n            const SizedBox(height: 12),\n            ElevatedButton.icon(\n              onPressed: () {},\n              icon: const Icon(Icons.image),\n              label: const Text('Upload Image'),\n            ),\n            const SizedBox(height: 16),\n            SizedBox(\n              width: double.infinity,\n              child: ElevatedButton(\n                onPressed: () => Navigator.pop(context),\n                child: const Text('Add Meme'),\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _showAnnouncementForm(BuildContext context) {\n    showModalBottomSheet(\n      context: context,\n      backgroundColor: AppColors.bgCard,\n      builder: (context) => Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Text(\n              'Create Announcement',\n              style: Theme.of(context).textTheme.headlineSmall,\n            ),\n            const SizedBox(height: 16),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Announcement Title',\n              ),\n            ),\n            const SizedBox(height: 12),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Message',\n              ),\n              maxLines: 4,\n            ),\n            const SizedBox(height: 16),\n            SizedBox(\n              width: double.infinity,\n              child: ElevatedButton(\n                onPressed: () => Navigator.pop(context),\n                child: const Text('Post Announcement'),\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _showQuestForm(BuildContext context) {\n    showModalBottomSheet(\n      context: context,\n      backgroundColor: AppColors.bgCard,\n      builder: (context) => Padding(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            Text(\n              'Create Daily Quest',\n              style: Theme.of(context).textTheme.headlineSmall,\n            ),\n            const SizedBox(height: 16),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Quest Name',\n              ),\n            ),\n            const SizedBox(height: 12),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Description',\n              ),\n            ),\n            const SizedBox(height: 12),\n            TextField(\n              decoration: const InputDecoration(\n                labelText: 'Reward Points',\n              ),\n              keyboardType: TextInputType.number,\n            ),\n            const SizedBox(height: 16),\n            SizedBox(\n              width: double.infinity,\n              child: ElevatedButton(\n                onPressed: () => Navigator.pop(context),\n                child: const Text('Create Quest'),\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n}\n